catalog_script_client.script:
function onLoad() {
    // Wait a brief moment for the portal widgets to finish loading
    setTimeout(function() {
        // Find the native Submit button
        var submitBtn = document.querySelector('button[name="submit"]');

        // If it exists and we haven't already added our Clear button...
        if (submitBtn && !document.getElementById('custom-clear-btn')) {

            // Create the new Clear button
            var clearBtn = document.createElement('button');
            clearBtn.id = 'custom-clear-btn';
            clearBtn.innerHTML = 'Clear';
            clearBtn.className = 'btn btn-default';

            // Apply matching premium styling
            clearBtn.style.cssText = 'border-radius: 8px; padding: 12px 35px; font-weight: 700; letter-spacing: 1px; text-transform: uppercase; background: #ffffff; color: #64748b; border: 2px solid #cbd5e1; transition: all 0.3s ease; margin-right: 15px; outline: none;';

            // Add red hover effects
            clearBtn.onmouseover = function() { this.style.borderColor = '#ef4444'; this.style.color = '#ef4444'; };
            clearBtn.onmouseout = function() { this.style.borderColor = '#cbd5e1'; this.style.color = '#64748b'; };

            // Tell the button to clear the form when clicked
            clearBtn.onclick = function(e) {
                e.preventDefault(); // Stop it from submitting
                var fields = g_form.getFieldNames();
                for (var i = 0; i < fields.length; i++) {
                    g_form.clearValue(fields[i]);
                }
            };

            // Insert it right next to the Submit button
            submitBtn.parentNode.insertBefore(clearBtn, submitBtn);
        }
    }, 800);
}
